        r = rng.random()
        if r < 0.45:
            ops.append('set'); args.append([rng.randint(0, length - 1), rng.randint(0, 1000)])
        elif r < 0.7:
            ops.append('snap'); args.append([]); snaps += 1
        else:
            if snaps == 0:
                ops.append('set'); args.append([rng.randint(0, length - 1), rng.randint(0, 1000)])
            else:
                ops.append('get'); args.append([rng.randint(0, length - 1), rng.randint(0, snaps - 1)])
    return [ops, args]

